const fs = require('fs');
const html = fs.readFileSync('/tmp/trending.html', 'utf-8');

// Quick & cheerfuler-like parse without dependencies
const repos = [];
const articles = html.match(/<article[^>]*class="[^"]*Box-row[^"]*"[^>]*>([\s\S]*?)<\/article>/g) || [];

function parseNumber(text) {
  if (!text) return 0;
  const clean = text.replace(/,/g, '').trim();
  if (clean.includes('k')) return Math.round(parseFloat(clean) * 1000);
  return parseInt(clean) || 0;
}

function decodeEntities(s) {
  return s.replace(/&/g, '&').replace(/</g, '<').replace(/>/g, '>').replace(/"/g, '"').replace(/&#39;/g, "'");
}

let count = 0;
for (const art of articles) {
  // Repo link in h2 > a
  const repoMatch = art.match(/<h2[^>]*>\s*<a[^>]*href="\/([^"]+)"[^>]*>/);
  if (!repoMatch) continue;
  const repoLink = repoMatch[1];
  if (repoLink.includes('/')) {
    const [owner, name] = repoLink.split('/');
    if (!owner || !name) continue;
  } else continue;

  // Sometimes h2 > a has nested spans; get href only

  // Description
  let description = '';
  const descMatch = art.match(/<p[^>]*class="[^"]*col-9[^"]*"[^>]*>([\s\S]*?)<\/p>/);
  if (descMatch) description = decodeEntities(descMatch[1].replace(/<[^>]+>/g, '').trim());

  // Language
  let language = '';
  const langMatch = art.match(/<span[^>]*itemprop="programmingLanguage"[^>]*>([\s\S]*?)<\/span>/);
  if (langMatch) language = langMatch[1].trim();

  // Stars (total)
  let stars = 0;
  const starsMatch = art.match(/<a[^>]*href="[^"]*\/stargazers"[^>]*>([\s\S]*?)<\/a>/);
  if (starsMatch) stars = parseNumber(starsMatch[1].replace(/<[^>]+>/g, '').trim());

  // Forks
  let forks = 0;
  const forksMatch = art.match(/<a[^>]*href="[^"]*\/forks"[^>]*>([\s\S]*?)<\/a>/);
  if (forksMatch) forks = parseNumber(forksMatch[1].replace(/<[^>]+>/g, '').trim());

  // Stars today/this week/month
  let starsPeriod = '';
  const periodMatch = art.match(/<span[^>]*class="[^"]*(?:d-inline-block\s+float-sm-right|float-sm-right)[^"]*"[^>]*>([\s\S]*?)<\/span>/);
  if (periodMatch) starsPeriod = periodMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();

  const [owner, name] = repoLink.split('/');
  repos.push({
    owner,
    name,
    fullName: `${owner}/${name}`,
    url: `https://github.com/${repoLink}`,
    description,
    language,
    stars,
    forks,
    starsPeriod
  });
}

console.log(JSON.stringify(repos, null, 2));
